// Solution
function fixTable(tableStr) {
  var rows = tableStr.split('<tr>')[1].split('</tr>')[0].split('</td>')[1].split('<td>');
  var correctedRows = [];
  for (var i = 0; i < rows.length; i++) {
    var cells = rows[i].split('</td>');
    if (cells.length === 1 && cells[0] === '') {
      correctedRows.push('<td>Default Cell</td>');
    } else {
      correctedRows.push(cells.join(''));
    }
  }
  return '<table>' + correctedRows.join('') + '</table>';
}
return fixTable;

