class Solution:
  def fix_table(self, table_str):
    rows = table_str.split('<tr>')[1].split('</tr>')[0].split('</td>')[1].split('<td>');
    corrected_rows = [];
    for i in range(len(rows)):
      cells = rows[i].split('</td>');
      if len(cells) == 1 and cells[0] == '' :
        corrected_rows.append('<td>Default Cell</td>');
      else:
        corrected_rows.append(cells[0]);
    return '<table>' + ''.join(corrected_rows) + '</table>
  return self.fix_table
